SPORTS = [
    {"hero":True,"sub":"Tennis","h3":"Wimbledon opens with Sinner and Djokovic in same half","summary":"The 2026 Championships begin main-draw play June 29, with the draw made June 26 and a loaded field at the All England Club.","body":["The 2026 Wimbledon Championships get underway on June 29 and run through July 12, with the singles draw revealed on June 26. World No.1 Jannik Sinner heads the men's field alongside seven-time champion Novak Djokovic, who landed in the same half of the bracket, plus Alexander Zverev.","On the women's side defending champion Iga Swiatek returns to defend her title. Qualifying ran June 22 to 25 ahead of the fortnight on the grass."],"sources":[("ATP Tour","https://www.atptour.com/en/news/wimbledon-2026-history-draw-schedule"),("Wimbledon","https://www.wimbledon.com/en_GB/news/wimbledon_2026_mens_singles_draw_preview")]},
    {"sub":"Tennis","h3":"Serena Williams takes a wild card into Wimbledon singles","summary":"The 44-year-old accepted the final women's singles wild card, her first Grand Slam singles appearance since the 2022 US Open.","body":["Serena Williams accepted a wild card into the Wimbledon 2026 women's singles draw, taking the eighth and final spot the All England Club held open. It marks her first major singles appearance since losing in the third round of the 2022 US Open.","Williams, a seven-time Wimbledon singles champion and 23-time major winner, will also contest the doubles with sister Venus. With no current ranking she could draw a top seed such as Swiatek or Sabalenka early."],"sources":[("ESPN","https://www.espn.com/tennis/story/_/id/49136493/serena-williams-play-wimbledon-singles-wild-card"),("WTA","https://www.wtatennis.com/news/4523474/serena-williams-to-return-to-singles-at-wimbledon-after-accepting-wild-card")]},
    {"sub":"Tennis","h3":"Madison Keys wins third Eastbourne title before Wimbledon","summary":"Keys swept past Tatjana Maria in the final, capping a dominant grass-court week as the majors tune-up wrapped up.","body":["Madison Keys claimed the Lexus Eastbourne Open for the third time in her career, beating former champion Tatjana Maria in straight sets. She reached the final after a 6-0, 6-1 demolition of Jessica Bouzas Maneiro in just 54 minutes.","Eastbourne was one of the last grass tune-ups before Wimbledon. In the wheelchair events Diede de Groot took the women's singles title and Britain's Gordon Reid won the men's draw."],"sources":[("LTA","https://www.lta.org.uk/fan-zone/lexus-eastbourne-open/news/2026-results-updates/")]},
    {"sub":"Formula 1","h3":"Norris wins Austrian Grand Prix to chew into Piastri lead","summary":"Lando Norris converted pole into his third win of 2026 at the Red Bull Ring, cutting the title gap to teammate Oscar Piastri.","body":["Lando Norris won the 2026 Austrian Grand Prix for McLaren, finishing clear of Ferrari's Charles Leclerc in second. The victory was his third of the season and trimmed the gap to championship leader and teammate Oscar Piastri.","Lewis Hamilton and George Russell rounded out the front-runners. The result tightened a McLaren-led title fight as the European leg of the calendar continued."],"sources":[("Motorsport","https://www.motorsport.com/f1/results/2026/austrian-gp-661669/"),("Autosport","https://www.autosport.com/f1/results/2026/austrian-gp-661671/")]},
    {"sub":"Formula 1","h3":"Antonelli leads the 2026 drivers standings heading into Austria","summary":"Kimi Antonelli topped the championship and qualified on pole at the Red Bull Ring as Mercedes set the early pace.","body":["Going into the Austrian Grand Prix weekend Kimi Antonelli led the drivers' championship with 156 points, 41 clear of Lewis Hamilton and 50 ahead of George Russell. Mercedes headed the constructors' table on 262 points from Ferrari and McLaren.","Antonelli took pole at the Red Bull Ring ahead of Oscar Piastri and Lando Norris, with George Russell fastest in final practice."],"sources":[("Sky Sports","https://www.skysports.com/f1/news/12433/13558224/austrian-gp-george-russell-tops-practice-three-from-kimi-antonelli-and-lewis-hamilton-to-set-up-thrilling-qualifying"),("Wikipedia","https://en.wikipedia.org/wiki/2026_Austrian_Grand_Prix")]},
    {"sub":"Sailing","h3":"Los Gallos take first SailGP win of the season in Canada","summary":"Diego Botin's Los Gallos won the Canada Sail Grand Prix final in Halifax, denying debutant Artemis a maiden victory.","body":["Los Gallos sealed their first event win of the 2026 SailGP season at the Canada Sail Grand Prix in Halifax. In Sunday's final they held off the Artemis SailGP Team, who were chasing a first-ever win in their debut campaign.","The result lifted Los Gallos into second in the championship standings and ended the run of dominance from the season's frontrunners."],"sources":[("SailGP","https://sailgp.com/betting/tips/canada-sail-grand-prix-recap-los-gallos-sailgp-teams-storms-to-halifax-win")]},
    {"sub":"Sailing","h3":"Slingsby's Flying Roos still lead SailGP overall","summary":"The BONDS Flying Roos hold a 16-point championship lead despite their winning streak ending in Canada.","body":["Tom Slingsby's BONDS Flying Roos remain top of the 2026 SailGP standings on 62 points, sixteen ahead of the field, even after their three-event winning streak ended at the Canada Sail Grand Prix.","Los Gallos and Emirates GBR are level on 44 points behind the Australians, setting up a tight fight as the global circuit heads toward its next stop."],"sources":[("Sail-World","https://www.sail-world.com/news/295980/Apex-Group-Bermuda-Sail-Grand-Prix-Overall"),("U.S. SailGP Team","https://www.ussailgpteam.com/standings")]},
    {"sub":"Football","h3":"World Cup knockout rounds begin as group stage closes","summary":"The 2026 FIFA World Cup reaches the round of 32 on June 28 after a dramatic final round of group matches.","body":["The expanded 2026 World Cup wrapped up its group stage over the weekend, with France beating Norway 4-1 and Senegal thrashing Iraq 5-0 on June 27. Belgium hammered New Zealand 5-1 and the United States edged Turkiye 3-2 earlier in the week.","The knockout phase opens June 28 with the round of 32, the first time the tournament reaches that stage under the 48-team format."],"sources":[("Olympics.com","https://www.olympics.com/en/news/fifa-world-cup-2026-schedule-results-scores-standings-list"),("ESPN","https://www.espn.com/soccer/story/_/id/48939282/2026-fifa-world-cup-fixtures-results-match-schedule-group-stage-knockout-rounds-bracket")]},
    {"sub":"Football","h3":"Sterling agrees Feyenoord move under Van Persie","summary":"Raheem Sterling has agreed to join Feyenoord on a deal running to the end of the season as he seeks regular football.","body":["Raheem Sterling has agreed to join Eredivisie side Feyenoord through the end of the season. Manager Robin van Persie said the England winger chose the Dutch club to regain the joy in his football.","Feyenoord planned to train in Belgium while Sterling awaited a Netherlands work permit. Elsewhere Heracles Almelo secured the signing of Rhys Bozinovski."],"sources":[("Football Oranje","https://www.football-oranje.com/"),("FootballTransfers","https://www.footballtransfers.com/en/transfer-news/nl-eredivisie")]},
    {"sub":"BJJ & Grappling","h3":"ADCC 2026 field takes shape for return to Europe","summary":"The road to the September ADCC World Championship in Krakow is set, with invites confirmed and 2024 gold medalists guaranteed spots.","body":["The field for the 2026 ADCC World Championship is filling out ahead of the September 12-13 event at Tauron Arena in Krakow, Poland, the competition's return to Europe for nearly a decade. Athletes who won gold in 2024 are guaranteed invitations.","The format features five male divisions of 16 athletes and three female divisions of eight. The event streams exclusively on FloGrappling."],"sources":[("FloGrappling","https://www.flograppling.com/articles/15999094-when-is-the-2026-no-gi-bjj-adcc-world-championship")]},
    {"sub":"BJJ & Grappling","h3":"IBJJF American Nationals and ADCC Windsor Open fill the mat calendar","summary":"Late June saw the IBJJF American National Championship broadcast and an ADCC Open in Windsor over the weekend.","body":["The 2026 American National IBJJF Jiu-Jitsu Championship ran June 25 to 27 on FloGrappling, keeping the gi competition calendar busy ahead of the summer's major no-gi events.","The ADCC Windsor Open followed on June 27-28, part of the broader ADCC open circuit feeding into the World Championship later in the year."],"sources":[("FloGrappling","https://www.flograppling.com/events/15616472-2026-american-national-ibjjf-jiu-jitsu-championship")]},
    {"sub":"Judo","h3":"Abe Uta sets record 12th Grand Slam gold in Ulaanbaatar","summary":"The IJF World Tour Ulaanbaatar Grand Slam delivered milestone wins as 2028 Olympic qualification points were on the line.","body":["At the Ulaanbaatar Grand Slam, held June 19-21 in Mongolia, Olympic and five-time world champion Abe Uta claimed her 12th Grand Slam gold in the women's -52 kg, a record for any woman, after her finalist could not compete.","Azerbaijan's Balabay Aghayev beat world champion Nagayama Ryuju for -60 kg gold, while Takeoka Takeshi and Omori Akari added titles for Japan. The event drew 454 judoka from 58 nations."],"sources":[("IJF.org","https://www.ijf.org/competition/3149"),("Wikipedia","https://en.wikipedia.org/wiki/2026_Judo_Grand_Slam_Ulaanbaatar")]},
]

